revised the above decorator to work even when DEV_USER and DEV_ROOM are not defined

`def local_development(func):
    def wrapped_func(*args, **kwargs):
        message = args[1]
        sender = message.sender
        room = message.room

        if hasattr(settings, "DEV_USER") and hasattr(settings, "DEV_ROOM"):
            if room and sender:
                if settings.DEV_ROOM == room['name'] and settings.DEV_USER == sender['name']:
                    return func(*args, **kwargs)

        else:
            return func(*args, **kwargs)

    return wrapped_func`

