`escape=False` for `detokenize` solves the issue!

I am using newest release. Just copying the code that you suggested:

```python
from pylatex.figure import Figure as Figure_, StandAloneGraphic

class Figure(Figure_):
    def add_image(self, filename, **_3to2kwargs):
        if 'placement' in _3to2kwargs: placement = _3to2kwargs['placement']; del _3to2kwargs['placement']
        else: placement = NoEscape(ur'\centering')
        if 'width' in _3to2kwargs: width = _3to2kwargs['width']; del _3to2kwargs['width']
        else: width = NoEscape(ur'0.8\textwidth')
        if width is not None:
            if self.escape:
                width = escape_latex(width)
            width = u'width=' + unicode(width)
        if placement is not None:
            self.append(placement)
        self.append(StandAloneGraphic(image_options=width,
                                      filename=fix_filename(filename)))

def fix_filename(path):
    path_parts = path.split('/' if os.name == 'posix' else '\\')
    dir_parts = path_parts[:-1]
    filename = path_parts[-1]
    file_parts = filename.split('.')
    if len(file_parts) > 2:
        filename = '{' + '.'.join(file_parts[0:-1]) + '}.' + file_parts[-1]
    dir_parts.append(filename)
    fixed_path = '/'.join(dir_parts)
    if '~' in fixed_path:
        fixed_path = NoEscape(r'\detokenize{' + fixed_path + '}')
    return fixed_path
```

