def annotate(self, text, properties=None, encoding=None):
        #''' set encoding to override the response to be interprited as the given encoding'''
        if not properties:
            properties = {}
        r = requests.get(
            self.server_url, params={
                'properties': str(properties)
            }, data=text)
        if encoding:
            r.encoding=encoding

