I'd fix this by defining a new sqlalchemy type, and using https://github.com/stefanofontanelli/ColanderAlchemy/pull/62:

```python
"""Defines SqlAlchemy types and other objects needed in _base."""
import collections
import json

import colander
from sqlalchemy.dialects import postgresql
from sqlalchemy import types


class JSONType(object):

    """Colander type which is able to serialize and deserialize JSON."""

    def serialize(self, node, appstruct):
        """Serialize JSON."""
        if appstruct is colander.null:
            return colander.null
        try:
            return json.dumps(appstruct)
        except Exception as e:
            raise colander.Invalid(node,
                                   '%s cannot be serialized: %s'
                                   % (appstruct, e))

    def deserialize(self, node, cstruct):
        """Deserialize JSON."""
        if cstruct is colander.null:
            return colander.null
        try:
            # use OrderedDict as order is important for us.
            return json.loads(cstruct,
                              object_pairs_hook=collections.OrderedDict)
        except Exception as e:
            raise colander.Invalid(node,
                                   '%s is not a JSON object: %s'
                                   % (cstruct, e))

    def cstruct_children(self, node, cstruct):
        """Used to determine the children of this type.

        As deserializing JSON also makes sure the children are correct
        we do not use this system.
        """
        return []


class JSON(types.TypeDecorator):

    """Copy of the postgresql.JSON type, with colanderalchemy config."""

    impl = postgresql.JSON

    __colanderalchemy_config__ = {'typ': JSONType}
```

Now I use the new `JSON` class where I want to be able to deserialize it.
