@wickman @kwlzn how's this for a solution?

1) search for` *.pth` files whenever a tainted path is detected in 'pex/pex.py'
2) use `path_from_pth` in `pex/util.py` to provide addtional paths to scrub

#### roughly how I'd implement `path_fom_pth` *it clearly doesn't meet guidelines for inclusion yet*
```python
import os, sys, traceback
from site import makepath

#based on site.addpackage
def path_from_pth(sitedir, name, known_paths):
  fullname = os.path.join(sitedir, name)
  namespace = {}
  local_vars = {
      'sitedir': sitedir,
      'name': name,
  }
  exec "import site" in namespace
  try:
    f = open(fullname, "rU")
  except IOError:
    return

  with f:
    for n, line in enumerate(f):
      if line.startswith("#"):
        continue
      try:
        if line.startswith(("import ", "import\t")):
          exec line in namespace, local_vars
          for mod in local_vars['sys'].modules.values():
            if hasattr(mod, '__path__'):
              dir, dircase = makepath(sitedir, *mod.__path__)
              if not dircase in known_paths and os.path.exists(dir):
                known_paths.add(dircase)
          continue
        line = line.rstrip()
        dir, dircase = makepath(sitedir, line)
        if not dircase in known_paths and os.path.exists(dir):
          known_paths.add(dircase)
      except Exception as err:
        print >>sys.stderr, "Error processing line {:d} of {}:\n".format(n + 1, fullname)
        for record in traceback.format_exception(*sys.exc_info()):
          for line in record.splitlines():
            print >>sys.stderr, '  '+line
        print >>sys.stderr, "\nRemainder of file ignored"
        break
  return known_paths

# example usage
if __name__ == '__main__':
  path = '/System/Library/Frameworks/Python.framework/Versions/2.7/Extras/lib/python'
  print addpackage(path, 'matplotlib-1.3.1-py2.7-nspkg.pth', set())

  path = '/Library/Python/2.7/site-packages'
  print addpackage(path, 'Extras.pth', set())
```

